const PROVIDER_ICON_COMPONENTS: Record<AIProvider, ProviderIconComponent> = {
  anthropic: ClaudeIcon,
  google: GeminiIcon,
  google_vertex: GoogleVertexIcon,
  openai: OpenAIIcon,
  vercel: VercelIcon,
  xai: XAIGrokIcon,
  azure: MicrosoftAzureIcon,
  amazon_bedrock: AmazonBedrockIcon,
  groq: GroqIcon,
  cohere: CohereIcon,
  moonshotai: KimiIcon,
  mistral: MistralAIIcon,
  ollama: OllamaIcon,
  openrouter: OpenRouterIcon,
};

export function ProviderIcon({
  className,
  decorative = true,
  provider,
}: ProviderIconProps) {
  const IconComponent = PROVIDER_ICON_COMPONENTS[provider];

  return (
    <IconComponent
      aria-hidden={decorative}
      aria-label={decorative ? undefined : PROVIDERS[provider].displayName}
      className={cx("h-5 w-5 shrink-0", className)}
      focusable="false"
    />
  );
}
